import xml.etree.ElementTree as ET
from django.contrib.auth.models import User
from django.contrib.sessions.backends.db import SessionStore

def handle_saml_post(request):
    # Parse the SAML POST response
    saml_response = request.POST['SAMLResponse']
    tree = ET.fromstring(saml_response)

    # Extract user information from assertion attributes
    nameid = tree.find('./{urn:oasis:names:tc:SAML:2.0:assertion}Subject').find('./{urn:oasis:names:tc:SAML:2.0:assertion}NameID').text
    email = tree.find('./{urn:oasis:names:tc:SAML:2.0:assertion}Attribute[@Name="email"]').text
    first_name = tree.find('./{urn:oasis:names:tc:SAML:2.0:assertion}Attribute[@Name="firstName"]').text
    last_name = tree.find('./{urn:oasis:names:tc:SAML:2.0:assertion}Attribute[@Name="lastName"]').text

    # Create a Django user session based on the NameID and attributes
    user, created = User.objects.get_or_create(nameid=nameid)
    if not created:
        user.email = email
        user.first_name = first_name
        user.last_name = last_name
        user.save()

    # Implement basic XML structure validation
    root = tree.getroot()
    ns = {'saml': 'urn:oasis:names:tc:SAML:2.0:assertion'}
    if root.tag != '{saml}Response':
        raise ValueError('Invalid SAML response')
    if root.find('./{saml}Status').attrib['Value'] != 'Success':
        raise ValueError('SAML status is not Success')
    if not root.find('./{saml}Assertion'):
        raise ValueError('No assertion found in SAML response')

    # Set the Django session store
    request.session = SessionStore()
    request.session['user'] = user

    return user